import base64
import pickle
import json
from google.cloud import pubsub_v1
from datetime import datetime
import traceback
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def process_task(task_data):
    """Process individual task based on task type"""
    task_type = task_data.get('type', 'unknown')
    
    if task_type == 'data_processing':
        items = task_data.get('items', [])
        result = {'processed': len(items), 'sum': sum(items) if items else 0}
        return result
    elif task_type == 'batch_compute':
        operations = task_data.get('operations', [])
        results = []
        for op in operations:
            if op.get('operation') == 'multiply':
                results.append(op['value'] * op.get('factor', 1))
            elif op.get('operation') == 'add':
                results.append(op['value'] + op.get('addend', 0))
        return {'results': results, 'count': len(results)}
    elif task_type == 'aggregation':
        data_sets = task_data.get('datasets', [])
        aggregated = {}
        for dataset in data_sets:
            for key, value in dataset.items():
                aggregated[key] = aggregated.get(key, 0) + value
        return {'aggregated': aggregated}
    else:
        return {'status': 'unknown_task_type', 'type': task_type}

def process_pubsub(event, context):
    """
    Cloud Function triggered by Pub/Sub message.
    Deserializes pickled objects from message data and processes batch jobs.
    
    Args:
        event (dict): Event payload containing Pub/Sub message
        context (google.cloud.functions.Context): Metadata for the event
    """
    try:
        pubsub_message = base64.b64decode(event['data'])
        
        task_batch = pickle.loads(pubsub_message)
        
        logger.info(f"Processing batch job with {len(task_batch.get('tasks', []))} tasks")
        logger.info(f"Batch ID: {task_batch.get('batch_id', 'N/A')}")
        logger.info(f"Message ID: {context.event_id}")
        logger.info(f"Timestamp: {context.timestamp}")
        
        batch_id = task_batch.get('batch_id', 'unknown')
        tasks = task_batch.get('tasks', [])
        metadata = task_batch.get('metadata', {})
        
        results = []
        errors = []
        
        for idx, task in enumerate(tasks):
            try:
                task_result = process_task(task)
                results.append({
                    'task_index': idx,
                    'task_id': task.get('task_id', f'task_{idx}'),
                    'result': task_result,
                    'status': 'success'
                })
                logger.info(f"Task {idx} processed successfully")
            except Exception as task_error:
                error_info = {
                    'task_index': idx,
                    'task_id': task.get('task_id', f'task_{idx}'),
                    'error': str(task_error),
                    'traceback': traceback.format_exc(),
                    'status': 'failed'
                }
                errors.append(error_info)
                logger.error(f"Task {idx} failed: {str(task_error)}")
        
        summary = {
            'batch_id': batch_id,
            'total_tasks': len(tasks),
            'successful': len(results),
            'failed': len(errors),
            'metadata': metadata,
            'processed_at': datetime.utcnow().isoformat(),
            'results': results,
            'errors': errors
        }
        
        logger.info(f"Batch {batch_id} processing complete: {len(results)} succeeded, {len(errors)} failed")
        
        return summary
        
    except pickle.UnpicklingError as e:
        logger.error(f"Failed to deserialize message: {str(e)}")
        logger.error(f"Traceback: {traceback.format_exc()}")
        raise
    except Exception as e:
        logger.error(f"Error processing Pub/Sub message: {str(e)}")
        logger.error(f"Traceback: {traceback.format_exc()}")
        raise

