def publish_sample_message():
    """Helper function to publish sample message to Pub/Sub"""
    from google.cloud import pubsub_v1
    
    project_id = "your-project-id"
    topic_id = "your-topic-id"
    
    publisher = pubsub_v1.PublisherClient()
    topic_path = publisher.topic_path(project_id, topic_id)
    
    batch = create_sample_batch()
    pickled_data = pickle.dumps(batch)
    encoded_data = base64.b64encode(pickled_data)
    
    future = publisher.publish(topic_path, encoded_data)
    message_id = future.result()
    
    logger.info(f"Published message {message_id} to {topic_path}")
    return message_id